const c = $input.first().json;
const text = (c.userText || '').toLowerCase();
const ids = c.ta_table_ids || {};

// ── Intent signals ──────────────────────────────────────────────
const isUmrah      = /umrah|hajj|makkah|madinah|saudi|ziyarat/i.test(text);
const isCar        = /\bcar\b|vehicle|rent|suv|sedan|bus|transport|cab|taxi/i.test(text);
const isItinerary  = /itinerar|day.?plan|day.?trip|schedule|program|\bplan\b|\btour\b/i.test(text);
const isService    = /visa|passport|attestat|apostil|insurance|service/i.test(text);
const isBooking    = /my.?book|booking|confirm|reserv|ticket|status/i.test(text);
// packages: anything travel-ish that isn't exclusively car/service/booking
const isPackage    = /package|holiday|trip|travel|tour|destination|dubai|kerala|europe|thailand|singapore|malaysia|maldives|kashmir|goa|international|domestic/i.test(text);

// Always fetch packages for general travel questions
const needsPackages    = !!(ids.packages    && (isPackage || isUmrah || (!isCar && !isService && !isBooking)));
const needsUmrah       = !!(ids.umrah_groups && isUmrah);
const needsCars        = !!(ids.cars        && isCar);
const needsItineraries = !!(ids.itineraries && (isItinerary || isPackage || isUmrah));
const needsServices    = !!(ids.services    && isService);
const needsBookings    = !!(ids.bookings    && isBooking);

// Keyword for name search (skip stop words)
const stopWords = new Set(['package','packages','rate','rates','price','cost','details','pls','please','tell','me','the','a','an','is','are','what','how','give','want','need','about','any','good','best','cheap','available','do','you','have','your','can','get']);
const words = text.split(/\s+/).filter(w => w.length > 2 && !stopWords.has(w));
const keyword = words[0] || '';

return [{ json: { ...c, _filter: { needsPackages, needsUmrah, needsCars, needsItineraries, needsServices, needsBookings, keyword } } }];

const c = $input.first().json;
const f = c._filter || {};
const ids = c.ta_table_ids || {};
const clientId = c.client_id;
const BASE = 'https://whizz.aiingo.com';
const TOKEN = 'nc_pat_n5dMpFolDUQNtkCWGiCJnX45xXWUoFnZdsQkwEyF';
const headers = { 'xc-token': TOKEN };
const kw = f.keyword || '';

async function fetch(tableId, extra = '') {
  if (!tableId) return [];
  try {
    const r = await $http.request({ method: 'GET', url: `${BASE}/api/v2/tables/${tableId}/records?where=(client_id,eq,${clientId})${extra}&limit=15`, headers });
    return r.list || [];
  } catch(e) { return []; }
}

const kwFilter = kw ? `~and(name,like,%${kw}%)` : '';
const today = new Date().toISOString().slice(0, 10);

const [packages, umrahGroups, cars, itineraries, services, bookings] = await Promise.all([
  f.needsPackages    ? fetch(ids.packages,    kwFilter) : [],
  f.needsUmrah       ? fetch(ids.umrah_groups, '&sort=departure_date') : [],
  f.needsCars        ? fetch(ids.cars,         '~and(status,eq,available)') : [],
  f.needsItineraries ? fetch(ids.itineraries,  kwFilter) : [],
  f.needsServices    ? fetch(ids.services,     '') : [],
  f.needsBookings    ? fetch(ids.bookings,     '&sort=-CreatedAt') : []
]);

return [{ json: { ...c,
  packages,
  umrahGroups: umrahGroups.filter(g => g.departure_date >= today),
  cars,
  itineraries,
  services,
  bookings
} }];

const { packages, umrahGroups, cars, itineraries, services, bookings } = $input.first().json;
const c = $input.first().json;
let block = '';

if (packages && packages.length) {
  const lines = packages.map(p => {
    let l = `- ${p.name}`;
    if (p.destination) l += ` | Destination: ${p.destination}`;
    if (p.nights)      l += ` | ${p.nights} nights`;
    if (p.type)        l += ` | Type: ${p.type}`;
    if (p.sell_price || p.base_price) l += ` | Price: ${p.currency||'INR'} ${p.sell_price||p.base_price}/person`;
    if (p.pax_min || p.pax_max) l += ` | Pax: ${p.pax_min||1}-${p.pax_max||''}`;
    try { const inc = JSON.parse(p.inclusions||'[]'); if (inc.length) l += ` | Includes: ${inc.join(', ')}`; } catch(e) {}
    return l;
  }).join('\n');
  block += '\n\n## Travel Packages\n' + lines;
}

if (umrahGroups && umrahGroups.length) {
  const lines = umrahGroups.map(g => `- ${g.name} | Departs: ${g.departure_date} | Seats: ${g.seats||0} | ${g.currency||'INR'} ${g.price_per_pax||''}/person`).join('\n');
  block += '\n\n## Upcoming Umrah / Hajj Groups\n' + lines;
}

if (itineraries && itineraries.length) {
  const lines = itineraries.map(it => {
    let days = []; try { days = JSON.parse(it.days||'[]'); } catch(e) {}
    return `- ${it.title||it.name}${it.destination?' | '+it.destination:''} | ${days.length} days`;
  }).join('\n');
  block += '\n\n## Itineraries\n' + lines;
}

if (cars && cars.length) {
  const lines = cars.map(car => `- ${car.name}${car.category?' ('+car.category+')':''} | ${car.seats||'?'} seats | ${car.currency||'INR'} ${car.daily_rate||0}/day${car.plate_no?' | Plate: '+car.plate_no:''}`).join('\n');
  block += '\n\n## Available Cars for Rent\n' + lines;
}

if (services && services.length) {
  const lines = services.map(s => `- ${s.name}${s.description?' | '+s.description:''} | ${s.currency||'INR'} ${s.price||''}`).join('\n');
  block += '\n\n## Services\n' + lines;
}

if (bookings && bookings.length) {
  const lines = bookings.map(b => `- Ref: ${b.Id} | ${b.package_name||b.name||''} | Status: ${b.status||''} | Date: ${b.travel_date||b.CreatedAt||''}`).join('\n');
  block += '\n\n## Recent Bookings\n' + lines;
}

return [{ json: { ...c, taContextBlock: block } }];
